import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';

function Home() {
  const [clientData, setClientData] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    try {
      const loggedInUser = localStorage.getItem('clientUser');
      if (loggedInUser) {
        setClientData(JSON.parse(loggedInUser));
      }
    } catch (error) {
      console.error("Error parsing user data:", error);
    }
  }, []);

  const handleCardAction = (type) => {
    if (type === 'payments') {
      alert("Redirecting to our Secure Payment Policy...");
    } else if (type === 'students') {
      navigate('/services'); 
    } else if (type === 'delivery') {
      navigate('/contact');
    }
  };

  return (
    <div className="home-page" style={{ fontFamily: "'Poppins', sans-serif", overflowX: 'hidden', backgroundColor: '#f8f9fa' }}>
      
      {/* 1. Hero Section */}
      <header className="hero-section text-white d-flex align-items-center" 
        style={{ 
          background: 'linear-gradient(135deg, #1e3c72 0%, #2a5298 100%)',
          minHeight: '70vh',
          padding: '80px 0'
        }}>
        <div className="container text-center">
          <h1 className="display-3 fw-bold mb-3" style={{ textShadow: '2px 4px 10px rgba(0,0,0,0.2)' }}>
            Freelance <span style={{ color: '#ffc107' }}>Hub Nashik</span>
          </h1>
          <p className="lead fs-4 mb-5 opacity-75 mx-auto" style={{ maxWidth: '800px' }}>
            The ultimate marketplace for skilled students and clients looking for top-tier solutions in Nashik.
          </p>
          <div className="d-flex justify-content-center gap-3 flex-wrap">
            <Link to="/services" className="btn btn-warning btn-lg px-5 py-3 fw-bold rounded-pill shadow-lg border-0">
              Explore Services
            </Link>
            <Link to="/contact" className="btn btn-outline-light btn-lg px-5 py-3 rounded-pill border-2">
              Contact Me
            </Link> 
          </div>
        </div>
      </header>

      {/* 2. Features Section */}
      <section className="py-5 bg-white border-top">
        <div className="container py-5 text-center">
          <div className="mb-5">
            <h2 className="fw-bold">Our Core Values</h2>
            <div className="mx-auto mt-2" style={{ width: '50px', height: '4px', background: '#ffc107', borderRadius: '10px' }}></div>
          </div>
          <div className="row g-4">
            <div className="col-md-4" onClick={() => handleCardAction('payments')} style={{ cursor: 'pointer' }}>
              <div className="p-4 rounded-4 feature-box bg-white shadow-sm h-100 border">
                <div className="display-5 mb-3 text-warning">🛡️</div>
                <h5 className="fw-bold">Secure Payments</h5>
                <p className="text-muted small">Safe escrow-based transactions for every project.</p>
              </div>
            </div>
            <div className="col-md-4" onClick={() => handleCardAction('students')} style={{ cursor: 'pointer' }}>
              <div className="p-4 rounded-4 feature-box bg-white shadow-sm h-100 border">
                <div className="display-5 mb-3 text-primary">🎓</div>
                <h5 className="fw-bold">Verified Talent</h5>
                <p className="text-muted small">Work with top-rated talent from verified backgrounds.</p>
              </div>
            </div>
            <div className="col-md-4" onClick={() => handleCardAction('delivery')} style={{ cursor: 'pointer' }}>
              <div className="p-4 rounded-4 feature-box bg-white shadow-sm h-100 border">
                <div className="display-5 mb-3 text-success">⚡</div>
                <h5 className="fw-bold">Fast Delivery</h5>
                <p className="text-muted small">Optimized workflows to ensure projects are on time.</p>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* 3. Client Feedback Section (NEW ADDED) */}
      <section className="py-5 bg-light border-top">
        <div className="container py-4">
          <div className="text-center mb-5">
            <h2 className="fw-bold">Client Feedback</h2>
            <div className="mx-auto mt-2" style={{ width: '50px', height: '4px', background: '#ffc107', borderRadius: '10px' }}></div>
            <p className="text-muted mt-3">What our clients in Nashik say about us</p>
          </div>

          <div className="row g-4">
            {[
              { name: "Amit Deshmukh", role: "Startup Founder", comment: "Excellent work on my website! The delivery was fast and professional." },
              { name: "Sonal Jadhav", role: "Marketing Manager", comment: "The design is top-notch. I highly recommend this platform for quality talent." },
              { name: "Rahul More", role: "Business Owner", comment: "Very secure and reliable. The payment process is really smooth." }
            ].map((feedback, index) => (
              <div className="col-md-4" key={index}>
                <div className="card h-100 border-0 shadow-sm p-4 rounded-4 bg-white feedback-card">
                  <div className="text-warning mb-3">⭐⭐⭐⭐⭐</div>
                  <p className="text-muted italic mb-3 text-start">"{feedback.comment}"</p>
                  <div className="d-flex align-items-center mt-auto">
                    <div className="bg-primary rounded-circle text-white d-flex align-items-center justify-content-center fw-bold" style={{ width: '40px', height: '40px' }}>
                      {feedback.name.charAt(0)}
                    </div>
                    <div className="ms-3 text-start">
                      <h6 className="mb-0 fw-bold">{feedback.name}</h6>
                      <small className="text-muted">{feedback.role}</small>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* 4. Nashik Location Section */}
      <section id="contact" className="py-5 bg-white">
        <div className="container text-center py-4">
          <h2 className="fw-bold mb-4">📍 Our Hub in <span className="text-primary">Nashik</span></h2>
          <div className="shadow-lg rounded-5 overflow-hidden mx-auto border border-white border-4" style={{ maxWidth: '1000px', height: '400px' }}>
            <iframe
              title="Nashik Map"
              src="https://google.com"
              width="100%" height="100%" style={{ border: 0 }} allowFullScreen="" loading="lazy"></iframe>
          </div>
        </div>
      </section>

      <style>{`
        .feature-box, .feedback-card {
          transition: all 0.3s ease;
        }
        .feature-box:hover, .feedback-card:hover {
          background: #fdfdfd;
          transform: translateY(-10px);
          box-shadow: 0 15px 30px rgba(0,0,0,0.1) !important;
          border-color: #ffc107 !important;
        }
      `}</style>

    </div>
  );
}

export default Home;
